const staticData = $getWorkflowStaticData('global');
const health = $input.first().json || {};
const feeds = Array.isArray(health.feeds) ? health.feeds : [];
const previous = staticData.feedAlertState || {};
const current = {};
const failing = [];

for (const feed of feeds) {
  const failures = Number(feed.consecutive_failures || 0);
  if (failures < 3) continue;
  const key = String(feed.url || feed.name || feed.id || 'unknown-feed');
  const item = {
    key,
    name: feed.name || key,
    url: feed.url || '',
    consecutive_failures: failures,
    last_error: feed.last_error || '',
    last_failed_at: feed.last_failed_at || '',
    last_status: feed.last_status || '',
  };
  current[key] = item;
  if (!previous[key]) failing.push(item);
}

const recovered = Object.keys(previous)
  .filter((key) => !current[key])
  .map((key) => previous[key]);

staticData.feedAlertState = current;
const shouldAlert = failing.length > 0 || recovered.length > 0;
const lines = [];
if (failing.length) {
  lines.push('新进入故障的 feed：');
  for (const feed of failing) {
    lines.push(`- ${feed.name} (${feed.url}) 连续失败 ${feed.consecutive_failures} 次；最近错误：${feed.last_error || '无'}`);
  }
}
if (recovered.length) {
  lines.push('已恢复的 feed：');
  for (const feed of recovered) {
    lines.push(`- ${feed.name} (${feed.url})`);
  }
}

return [{
  json: {
    shouldAlert,
    failing,
    recovered,
    checked_at: new Date().toISOString(),
    subject: failing.length ? `feed告警：${failing.length}个信源连续失败` : `feed恢复：${recovered.length}个信源恢复`,
    text: lines.join('\n'),
    html: `<pre>${lines.join('\n').replace(/[&<>]/g, (c) => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;' }[c]))}</pre>`,
  },
}];
